unit lipdecide;

interface

uses globals, math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
begin
  if abs(A - B) < 0.000001 then
    REALCOMPARE := EQ
  else if A < B then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

function Dist(x1, y1, x2, y2: real): real;
begin
  Dist := sqrt(sqr(x1 - x2) + sqr(y1 - y2));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := 0.5 * abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
end;

function InOrOnCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  a, b, c: real;
  sidesSq: array[1..3] of real;
  maxSideSq: real;
  otherSumSq: real;
  r: real;
begin
  a := Dist(x1, y1, x2, y2);
  b := Dist(x2, y2, x3, y3);
  c := Dist(x3, y3, x1, y1);

  sidesSq[1] := sqr(a);
  sidesSq[2] := sqr(b);
  sidesSq[3] := sqr(c);

  maxSideSq := sidesSq[1];
  otherSumSq := sidesSq[2] + sidesSq[3];
  if sidesSq[2] > maxSideSq then
  begin
    maxSideSq := sidesSq[2];
    otherSumSq := sidesSq[1] + sidesSq[3];
  end;
  if sidesSq[3] > maxSideSq then
  begin
    maxSideSq := sidesSq[3];
    otherSumSq := sidesSq[1] + sidesSq[2];
  end;

  if REALCOMPARE(maxSideSq, otherSumSq) <> LT then
    r := sqrt(maxSideSq) / 2.0
  else
    r := (a * b * c) / sqrt(abs((a + b + c) * (b + c - a) * (c + a - b) * (a + b - c)));

  InOrOnCircle := REALCOMPARE(r, radius) <> GT;
end;

function GetQuadrant(x, y: real): integer;
begin
  if (REALCOMPARE(x, 0.0) <> LT) and (REALCOMPARE(y, 0.0) <> LT) then
    GetQuadrant := 1
  else if (REALCOMPARE(x, 0.0) = LT) and (REALCOMPARE(y, 0.0) <> LT) then
    GetQuadrant := 2
  else if (REALCOMPARE(x, 0.0) <> GT) and (REALCOMPARE(y, 0.0) = LT) then
    GetQuadrant := 3
  else
    GetQuadrant := 4;
end;

procedure DECIDE;
var
  i, j, k: integer;
  quadsUsed: array[1..4] of boolean;
  qCount: integer;
  angle, p1p2, p2p3: real;
  v1x, v1y, v2x, v2y, temp: real;
  lineDist, numerator, denominator: real;
  cond1, cond2: boolean;
  rowAllTrue: boolean;
begin
  { Initialize CMV }
  for i := 1 to 15 do CMV[i] := false;

  { LIC 1 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
      CMV[1] := true;

  { LIC 2 }
  for i := 1 to NUMPOINTS - 2 do
    if not InOrOnCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAMETERS.RADIUS1) then
      CMV[2] := true;

  { LIC 3 }
  for i := 1 to NUMPOINTS - 2 do
  begin
    p1p2 := Dist(X[i], Y[i], X[i+1], Y[i+1]);
    p2p3 := Dist(X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if (REALCOMPARE(p1p2, 0.0) <> EQ) and (REALCOMPARE(p2p3, 0.0) <> EQ) then
    begin
      v1x := X[i] - X[i+1]; v1y := Y[i] - Y[i+1];
      v2x := X[i+2] - X[i+1]; v2y := Y[i+2] - Y[i+1];
      temp := (v1x * v2x + v1y * v2y) / (p1p2 * p2p3);
      if temp > 1.0 then temp := 1.0 else if temp < -1.0 then temp := -1.0;
      angle := arccos(temp);
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        CMV[3] := true;
    end;
  end;

  { LIC 4 }
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]), PARAMETERS.AREA1) = GT then
      CMV[4] := true;

  { LIC 5 }
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for k := 1 to 4 do quadsUsed[k] := false;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
      quadsUsed[GetQuadrant(X[j], Y[j])] := true;
    qCount := 0;
    for k := 1 to 4 do if quadsUsed[k] then qCount := qCount + 1;
    if qCount > PARAMETERS.QUADS then CMV[5] := true;
  end;

  { LIC 6 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i+1], X[i]) = LT then CMV[6] := true;

  { LIC 7 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      j := i + PARAMETERS.N_PTS - 1;
      if (REALCOMPARE(X[i], X[j]) = EQ) and (REALCOMPARE(Y[i], Y[j]) = EQ) then
      begin
        for k := i + 1 to j - 1 do
          if REALCOMPARE(Dist(X[k], Y[k], X[i], Y[i]), PARAMETERS.DIST) = GT then
            CMV[7] := true;
      end
      else
      begin
        denominator := Dist(X[i], Y[i], X[j], Y[j]);
        for k := i + 1 to j - 1 do
        begin
          numerator := abs((Y[j] - Y[i]) * X[k] - (X[j] - X[i]) * Y[k] + X[j] * Y[i] - Y[j] * X[i]);
          if REALCOMPARE(numerator / denominator, PARAMETERS.DIST) = GT then
            CMV[7] := true;
        end;
      end;
    end;

  { LIC 8 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
      if REALCOMPARE(Dist(X[i], Y[i], X[i+PARAMETERS.K_PTS+1], Y[i+PARAMETERS.K_PTS+1]), PARAMETERS.LENGTH1) = GT then
        CMV[8] := true;

  { LIC 9 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1; k := j + PARAMETERS.B_PTS + 1;
      if not InOrOnCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
        CMV[9] := true;
    end;

  { LIC 10 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1; k := j + PARAMETERS.D_PTS + 1;
      p1p2 := Dist(X[i], Y[i], X[j], Y[j]); p2p3 := Dist(X[j], Y[j], X[k], Y[k]);
      if (REALCOMPARE(p1p2, 0.0) <> EQ) and (REALCOMPARE(p2p3, 0.0) <> EQ) then
      begin
        v1x := X[i] - X[j]; v1y := Y[i] - Y[j];
        v2x := X[k] - X[j]; v2y := Y[k] - Y[j];
        temp := (v1x * v2x + v1y * v2y) / (p1p2 * p2p3);
        if temp > 1.0 then temp := 1.0 else if temp < -1.0 then temp := -1.0;
        angle := arccos(temp);
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
          CMV[10] := true;
      end;
    end;

  { LIC 11 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1; k := j + PARAMETERS.F_PTS + 1;
      if REALCOMPARE(TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]), PARAMETERS.AREA1) = GT then
        CMV[11] := true;
    end;

  { LIC 12 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
      if REALCOMPARE(X[i+PARAMETERS.G_PTS+1], X[i]) = LT then CMV[12] := true;

  { LIC 13 }
  if NUMPOINTS >= 3 then
  begin
    cond1 := false; cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      temp := Dist(X[i], Y[i], X[i+PARAMETERS.K_PTS+1], Y[i+PARAMETERS.K_PTS+1]);
      if REALCOMPARE(temp, PARAMETERS.LENGTH1) = GT then cond1 := true;
      if REALCOMPARE(temp, PARAMETERS.LENGTH2) = LT then cond2 := true;
    end;
    if cond1 and cond2 then CMV[13] := true;
  end;

  { LIC 14 }
  if NUMPOINTS >= 5 then
  begin
    cond1 := false; cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1; k := j + PARAMETERS.B_PTS + 1;
      if not InOrOnCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then cond1 := true;
      if InOrOnCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then cond2 := true;
    end;
    if cond1 and cond2 then CMV[14] := true;
  end;

  { LIC 15 }
  if NUMPOINTS >= 5 then
  begin
    cond1 := false; cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1; k := j + PARAMETERS.F_PTS + 1;
      temp := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(temp, PARAMETERS.AREA1) = GT then cond1 := true;
      if REALCOMPARE(temp, PARAMETERS.AREA2) = LT then cond2 := true;
    end;
    if cond1 and cond2 then CMV[15] := true;
  end;

  { PUM }
  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
        end;

  { FUV }
  for i := 1 to 15 do
    if not PUM[i, i] then FUV[i] := true
    else
    begin
      rowAllTrue := true;
      for j := 1 to 15 do if (i <> j) and (not PUM[i, j]) then rowAllTrue := false;
      FUV[i] := rowAllTrue;
    end;

  { LAUNCH }
  LAUNCH := true;
  for i := 1 to 15 do if not FUV[i] then LAUNCH := false;
end;

end.
